The round 2 problem is a combination of Greedy and Backtracking. Here's my solution. Please feel free to correct it !
```
    int max = Integer.MIN_VALUE;
    public int getMax(int[][] matrix, int k) {
        Collections.sort(Arrays.asList(matrix), new Comparator<int[]>() {
            @Override
            public int compare(int[] a, int[] b) {
                return a[0] == b[0] ? b[1] - a[1] : a[0] - b[0];
            }
        });

        backtrack(matrix, k, 0, new LinkedList<>());
        return max;
    }

    public void backtrack(int[][] matrix, int k, int idx, LinkedList<int[]> slots) {
        if (slots.size() > k) {
            return;
        }
        if (slots.size() == k || idx >=  matrix.length) {
            max = Math.max(getCost(slots), max);
        }

        for (int i = idx; i < matrix.length; i++) {
            if (slots.isEmpty()) {
                slots.addLast(matrix[i]);
                continue;
            }

            if (slots.peekLast()[1] >= matrix[i][0]) {
                LinkedList<int[]> subset = new LinkedList<>(slots);
                backtrack(matrix, k,i+1, slots);
                subset.pollLast();
                subset.addLast(matrix[i]);
                backtrack(matrix,k,i+1,subset);
            } else {
                slots.addLast(matrix[i]);
            }

            if (slots.size() == k) {
                max = Math.max(max, getCost(slots));
            }
        }

    }

    public int getCost(LinkedList<int[]> slots) {
        int sum  = 0;
        for (int[] slot : slots) {
            sum+= slot[2];
        }

        return sum;
    }
```

